import { UnionFind } from './UnionFind';

/**
 * @param {number} n
 * @param {number[][]} edges
 * @param {number} k
 * @return {number}
 */
function solve(n, edges, k) {
    // Sort edges by weight in ascending order
    edges.sort((a, b) => a[2] - b[2]);

    // Initialize Union-Find structure
    const uf = new UnionFind(n);

    // Keep track of the maximum cost
    let maxCost = 0;

    // Iterate through edges and try to split the graph into k components
    for (const [u, v, w] of edges) {
        // Check if u and v are already in the same component
        if (uf.find(u) !== uf.find(v)) {
            // If splitting the graph into k components is possible, break
            if (uf.components === k - 1) {
                break;
            }
            // Union the components
            uf.union(u, v);
            // Update the maximum cost
            maxCost = Math.max(maxCost, w);
        }
    }

    return maxCost;
}

class UnionFind {
    constructor(n) {
        this.parent = Array(n).fill(0).map((_, i) => i);
        this.rank = Array(n).fill(0);
        this.components = n;
    }

    find(x) {
        if (this.parent[x] !== x) {
            this.parent[x] = this.find(this.parent[x]);
        }
        return this.parent[x];
    }

    union(x, y) {
        const xRoot = this.find(x);
        const yRoot = this.find(y);

        if (xRoot === yRoot) {
            return false;
        }

        if (this.rank[xRoot] < this.rank[yRoot]) {
            this.parent[xRoot] = yRoot;
        } else {
            this.parent[yRoot] = xRoot;
            if (this.rank[xRoot] === this.rank[yRoot]) {
                this.rank[xRoot]++;
            }
        }

        this.components--;
        return true;
    }
}

